using System.Collections;
using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// Mostra uma ou mais linhas de diálogo, cada uma com o seu próprio falante
/// (Self/Player/Outro NPC, ver DialogueLine), com efeito de escrita se houver
/// um INpcDialogueDisplay configurado em "Dialogue Display" no NpcController.
/// </summary>
[System.Serializable]
public class Action_Dialogue : NpcAction
{
    public List<DialogueLine> lines = new List<DialogueLine>();

    [Tooltip("Caracteres por segundo do efeito de escrita. 0 = instantâneo.")]
    public float charsPerSecond = 30f;

    public override IEnumerator Execute(NpcController npc)
    {
        var display = npc.DialogueDisplay;

        foreach (var line in lines)
        {
            if (line == null) continue;

            string speakerName = line.ResolveSpeakerName(npc);

            if (display != null)
            {
                yield return display.ShowLine(npc, speakerName, line.text, charsPerSecond, line.ResolveSpeakerTransform(npc));
            }
            else
            {
                Debug.Log(string.IsNullOrEmpty(speakerName) ? line.text : $"{speakerName}: {line.text}");
                yield return null;
            }
        }

        display?.Hide(npc);
    }
}

/// <summary>Espera um número de segundos antes de continuar para a próxima ação.</summary>
[System.Serializable]
public class Action_Wait : NpcAction
{
    public float seconds = 1f;

    public override IEnumerator Execute(NpcController npc)
    {
        if (seconds > 0f) yield return NpcActionUtil.Wait(seconds);
    }
}

/// <summary>Move o NPC numa direção fixa, a uma velocidade, durante um tempo (via NpcMovement).</summary>
[System.Serializable]
public class Action_MoveNpc : NpcAction
{
    public Vector2 direction = Vector2.right;
    public float speed = 2f;
    public float duration = 1f;

    [Tooltip("Se activo, espera o movimento terminar antes de avançar para a próxima ação. Se desactivo, o movimento corre em paralelo com as ações seguintes.")]
    public bool waitForCompletion = true;

    public override IEnumerator Execute(NpcController npc)
    {
        var movement = npc.Movement;
        if (movement == null)
        {
            Debug.LogWarning($"[{npc.name}] Action_MoveNpc: NpcMovement não encontrado.");
            yield break;
        }

        if (waitForCompletion)
        {
            yield return movement.MoveDirectionForTime(direction, speed, duration);
        }
        else
        {
            npc.StartCoroutine(movement.MoveDirectionForTime(direction, speed, duration));
        }
    }
}

// ─── Task #33 — Diálogo multi com probabilidade ───────────────────────────

/// <summary>
/// Uma entrada numa lista de falas com peso de probabilidade.
/// Peso relativo (não precisa de somar 100): 1+1+2 → 25%/25%/50%.
/// </summary>
[System.Serializable]
public class WeightedDialogueLine
{
    [Tooltip("Fala a mostrar se esta entrada for sorteada.")]
    public DialogueLine line;

    [Tooltip("Peso relativo de ser sorteada (ex: 1 = mesma probabilidade de todas as outras com peso 1; 2 = o dobro).")]
    [Min(0f)] public float weight = 1f;
}

/// <summary>
/// Sorteia aleatoriamente UMA linha de diálogo de até 5 entradas com peso
/// de probabilidade configurável no Inspector.
///
/// Útil para NPCs com falas variadas consoante o encontro — por exemplo,
/// um guarda que diz coisas diferentes cada vez que o player passa:
///   • "Circula." (peso 3)
///   • "Não fiques aqui." (peso 2)
///   • "Vai embora." (peso 1)
///
/// A linha sorteada é mostrada exactamente como em Action_Dialogue (mesmo
/// balão, mesmo efeito de escrita). Se todos os pesos forem 0 ou a lista
/// estiver vazia, não faz nada.
///
/// Limite de 5 entradas por razões de Inspector — para listas maiores,
/// considera usar eventos separados com Condition_Chance (ainda não
/// existe, mas pode ser adicionado).
/// </summary>
[System.Serializable]
public class Action_RandomDialogue : NpcAction
{
    [Tooltip("Lista de falas possíveis (máx. 5 entradas — ver documentação).")]
    public WeightedDialogueLine[] entries = new WeightedDialogueLine[0];

    [Tooltip("Caracteres por segundo do efeito de escrita. 0 = instantâneo.")]
    public float charsPerSecond = 30f;

    public override IEnumerator Execute(NpcController npc)
    {
        if (entries == null || entries.Length == 0) yield break;

        // Calcular total de pesos.
        float totalWeight = 0f;
        foreach (var e in entries)
            if (e != null && e.weight > 0f) totalWeight += e.weight;

        if (totalWeight <= 0f) yield break;

        // Sortear.
        float roll = Random.Range(0f, totalWeight);
        WeightedDialogueLine chosen = null;
        float cumulative = 0f;
        foreach (var e in entries)
        {
            if (e == null || e.weight <= 0f) continue;
            cumulative += e.weight;
            if (roll <= cumulative) { chosen = e; break; }
        }
        if (chosen == null || chosen.line == null) yield break;

        // Mostrar exactamente como Action_Dialogue.
        var display = npc.DialogueDisplay;
        string speakerName = chosen.line.ResolveSpeakerName(npc);

        if (display != null)
            yield return display.ShowLine(npc, speakerName, chosen.line.text, charsPerSecond, chosen.line.ResolveSpeakerTransform(npc));
        else
            Debug.Log(string.IsNullOrEmpty(speakerName) ? chosen.line.text : $"{speakerName}: {chosen.line.text}");

        display?.Hide(npc);
    }
}

/// <summary>Mostra um menu de escolhas ao player; a escolha seleccionada pode activar outro NpcEvent.</summary>
[System.Serializable]
public class Action_ShowChoices : NpcAction
{
    public List<NpcChoice> choices = new List<NpcChoice>();

    public override IEnumerator Execute(NpcController npc)
    {
        var menu = npc.ChoiceMenu;
        if (menu == null || choices.Count == 0)
        {
            Debug.LogWarning($"[{npc.name}] Action_ShowChoices: nenhum menu de escolhas atribuído ou lista de escolhas vazia.");
            yield break;
        }

        int selected = -1;
        yield return menu.Show(npc, choices, result => selected = result);

        if (selected >= 0 && selected < choices.Count)
        {
            string targetId = choices[selected].targetEventId;
            if (!string.IsNullOrEmpty(targetId))
                npc.ActivateEventById(targetId);
        }
    }
}
